"""COCO Panoptic format normalizer.

Reads a COCO panoptic annotation JSON together with the corresponding
image and mask directories, and yields column-oriented batches suitable
for ``Client.ingest()``.

No external dependencies — uses only stdlib ``json`` and ``pathlib``.
The panoptic JSON is a simple structure we can parse directly (no
``pycocotools`` required).

COCO panoptic JSON structure::

    {
        "images": [
            {"id": 1, "file_name": "000001.jpg", "width": 640, "height": 480},
            ...
        ],
        "annotations": [
            {"image_id": 1, "file_name": "000001.png",
             "segments_info": [{"id": 1, "category_id": 1, "area": 500}, ...]},
            ...
        ],
        "categories": [
            {"id": 1, "name": "person", "supercategory": "human"},
            ...
        ]
    }

Columns produced per image (one row per image):

================  =====  ================================================
Column            Type   Content
================  =====  ================================================
coco_image_id     int    COCO image ID
image             bytes  Source image file bytes
mask              bytes  Panoptic mask PNG bytes (None if missing)
width             int    Image width
height            int    Image height
filename          str    Original image filename
mask_filename     str    Panoptic mask PNG filename
segments_info     str    JSON-encoded segments_info list
categories        str    JSON-encoded category list (same for all)
================  =====  ================================================

After file registration by the SDK, two extra columns are added:

================  =====  ================================================
image_id          str    UUID referencing image in files table
mask_id           str    UUID referencing mask in files table
================  =====  ================================================
"""

from __future__ import annotations

import json as _json
import logging
from pathlib import Path
from typing import Iterator, Dict, List, Any, Union

from .base import Format

logger = logging.getLogger(__name__)


class CocoPanoptic(Format):
    """Format object for COCO panoptic segmentation datasets.

    Encapsulates the inter-file relationships between annotation JSON,
    source images, and panoptic mask PNGs.

    Args:
        images_dir: Directory containing source images.
        masks_dir: Directory containing panoptic mask PNGs.
        annotations: Path to the COCO panoptic annotation JSON file.
        batch_size: Number of images per yielded batch (default 100).

    Example:
        >>> from deeplake.managed.formats import CocoPanoptic
        >>> fmt = CocoPanoptic(
        ...     images_dir="coco/train2017",
        ...     masks_dir="coco/panoptic_train2017",
        ...     annotations="coco/annotations/panoptic_train2017.json",
        ... )
        >>> client.ingest("panoptic", format=fmt)
    """

    def __init__(
        self,
        images_dir: Union[str, Path],
        masks_dir: Union[str, Path],
        annotations: Union[str, Path],
        *,
        batch_size: int = 100,
    ):
        self.images_dir = Path(images_dir)
        self.masks_dir = Path(masks_dir)
        self.annotations = Path(annotations)
        self.batch_size = batch_size

    def schema(self) -> Dict[str, str]:
        """Return deeplake column type hints for ``_ensure_columns``.

        These control which deeplake storage types are used.  Binary
        file data should use ``"BINARY"`` (raw bytes) rather than typed
        formats like ``"IMAGE"`` which attempt to decode the bytes into
        pixel arrays.  The pg_deeplake domain types (IMAGE, SEGMENT_MASK)
        are applied separately via ``pg_schema()``.
        """
        return {
            "image": "BINARY",
            "mask": "BINARY",
        }

    def pg_schema(self) -> Dict[str, str]:
        """Return pg_deeplake domain type overrides for ALTER TABLE after creation.

        These map column names to PostgreSQL domain types defined in
        pg_deeplake (e.g. IMAGE, SEGMENT_MASK).  Applied after
        ``create_deeplake_table()`` which creates BYTEA columns.
        """
        return {
            "image": "IMAGE",
            "mask": "SEGMENT_MASK",
        }

    def normalize(self) -> Iterator[Dict[str, List[Any]]]:
        """Yield column-oriented batches from the COCO panoptic dataset.

        Each batch is a ``dict[str, list]`` with ``batch_size`` rows
        (or fewer for the final batch).

        Raises:
            FileNotFoundError: If annotations file or a required directory
                does not exist.
        """
        if not self.annotations.exists():
            raise FileNotFoundError(
                f"Annotations file not found: {self.annotations}"
            )
        if not self.images_dir.is_dir():
            raise FileNotFoundError(
                f"Images directory not found: {self.images_dir}"
            )
        if not self.masks_dir.is_dir():
            raise FileNotFoundError(
                f"Masks directory not found: {self.masks_dir}"
            )

        with open(self.annotations) as f:
            coco = _json.load(f)

        # Build lookup: image_id -> annotation
        ann_by_image = {a["image_id"]: a for a in coco.get("annotations", [])}
        categories_json = _json.dumps(coco.get("categories", []))

        batch: List[Dict[str, Any]] = []

        for img_info in coco.get("images", []):
            image_id = img_info["id"]
            img_path = self.images_dir / img_info["file_name"]

            if not img_path.exists():
                logger.warning("Image not found, skipping: %s", img_path)
                continue

            ann = ann_by_image.get(image_id)
            if ann is None:
                logger.warning(
                    "No annotation for image %s, skipping", image_id
                )
                continue

            mask_path = self.masks_dir / ann["file_name"]
            mask_bytes = mask_path.read_bytes() if mask_path.exists() else None

            batch.append(
                {
                    "coco_image_id": image_id,
                    "image": img_path.read_bytes(),
                    "mask": mask_bytes,
                    "width": img_info.get("width", 0),
                    "height": img_info.get("height", 0),
                    "filename": img_info["file_name"],
                    "mask_filename": ann["file_name"],
                    "segments_info": _json.dumps(
                        ann.get("segments_info", [])
                    ),
                    "categories": categories_json,
                }
            )

            if len(batch) >= self.batch_size:
                yield {k: [d[k] for d in batch] for k in batch[0]}
                batch = []

        if batch:
            yield {k: [d[k] for d in batch] for k in batch[0]}
